solution_code:
#include <iostream>

int addAndTotal(int value) {
    static int total = 0;
    total += value;
    return total;
}

int main() {
    std::cout << addAndTotal(5)  << "\n";
    std::cout << addAndTotal(-2) << "\n";
    std::cout << addAndTotal(8)  << "\n";
    return 0;
}

