solution_code:
#include <iostream>

inline const int kZeroThreshold = 0;

int processValue(int x) {
    if (x > kZeroThreshold) return x * 2;
    if (x < kZeroThreshold) return x / 2;
    return 0;
}

int main() {
    int val;
    std::cin >> val;
    std::cout << processValue(val) << "\n";
    return 0;
}
